import{_ as e,o as i,c as r,a2 as l}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Pemecahan Masalah","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting.md","filePath":"troubleshooting.md"}'),o={name:"troubleshooting.md"};function n(t,a,s,d,h,c){return i(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="pemecahan-masalah" tabindex="-1">Pemecahan Masalah <a class="header-anchor" href="#pemecahan-masalah" aria-label="Permalink to &quot;Pemecahan Masalah&quot;">​</a></h1><h2 id="kamera-tidak-terdeteksi" tabindex="-1">Kamera Tidak Terdeteksi <a class="header-anchor" href="#kamera-tidak-terdeteksi" aria-label="Permalink to &quot;Kamera Tidak Terdeteksi&quot;">​</a></h2><ol><li>Pastikan kamera terhubung dan terinstall drivernya</li><li>Izinkan akses kamera di browser (klik ikon gembok di address bar)</li><li>Restart browser</li><li>Coba browser lain (Chrome/Edge sangat disarankan)</li></ol><h2 id="ai-opencv-error" tabindex="-1">AI OpenCV Error <a class="header-anchor" href="#ai-opencv-error" aria-label="Permalink to &quot;AI OpenCV Error&quot;">​</a></h2><ol><li>Pastikan Python 3 terinstall</li><li>Install OpenCV: <code>pip install opencv-python numpy</code></li><li>Restart server <code>node server.mjs</code></li><li>Cek log terminal untuk pesan error detail</li></ol><h2 id="mediapipe-tidak-berfungsi" tabindex="-1">MediaPipe Tidak Berfungsi <a class="header-anchor" href="#mediapipe-tidak-berfungsi" aria-label="Permalink to &quot;MediaPipe Tidak Berfungsi&quot;">​</a></h2><ol><li>Pastikan file WASM ada di <code>public/wasm/</code></li><li>Gunakan browser modern (Chrome 80+)</li><li>Pastikan model file ada di <code>public/models/efficientdet_lite0.tflite</code></li></ol><h2 id="sinkronisasi-gagal" tabindex="-1">Sinkronisasi Gagal <a class="header-anchor" href="#sinkronisasi-gagal" aria-label="Permalink to &quot;Sinkronisasi Gagal&quot;">​</a></h2><ol><li>Cek pengaturan jaringan di tab <strong>Jaringan</strong></li><li>Pastikan URL Hub/Cloud benar dan dapat dijangkau</li><li>Cek koneksi jaringan</li><li>Cek log server untuk pesan error sinkronisasi</li></ol><h2 id="lupa-password-admin" tabindex="-1">Lupa Password Admin <a class="header-anchor" href="#lupa-password-admin" aria-label="Permalink to &quot;Lupa Password Admin&quot;">​</a></h2><p>Password admin default: <code>password</code>. Jika dirubah dan lupa, hubungi administrator sistem atau reset database dengan menghapus file <code>xray.db</code>.</p><h2 id="kesalahan-saat-import-excel" tabindex="-1">Kesalahan saat Import Excel <a class="header-anchor" href="#kesalahan-saat-import-excel" aria-label="Permalink to &quot;Kesalahan saat Import Excel&quot;">​</a></h2><ol><li>Pastikan format file <code>.xls</code> atau <code>.xlsx</code></li><li>Gunakan template yang tersedia di folder <code>templates/</code></li><li>Pastikan nama kolom sesuai dengan template</li></ol>',13)])])}const u=e(o,[["render",n]]);export{m as __pageData,u as default};
